const input = $input.first().json;
const query = input.query || {};
const { search, estado, lead_tipo, origen, limit = 50, offset = 0 } = query;

const searchPattern = search ? `%${search}%` : '%';
const allowedEstados = ['NUEVO', 'FRIO', 'TIBIO', 'CALIENTE'];
const estadoFilter = estado && allowedEstados.includes(estado) ? `estado = '${estado}'` : `estado IN ('NUEVO','FRIO','TIBIO','CALIENTE')`;

const queryList = `SELECT id, nombre, apellido, whatsapp, email, lead_tipo, origen, nivel, estado, resumen, ultimo_contacto, created_at FROM leads
WHERE (nombre ILIKE '${searchPattern}' OR whatsapp ILIKE '${searchPattern}' OR email ILIKE '${searchPattern}')
AND (${estadoFilter})
AND (${lead_tipo ? `lead_tipo = '${lead_tipo}'` : 'true'})
AND (${origen ? `origen = '${origen}'` : 'true'})
ORDER BY ultimo_contacto DESC NULLS LAST
LIMIT ${parseInt(limit)} OFFSET ${parseInt(offset)};`;

const queryCount = `SELECT COUNT(*) as total FROM leads
WHERE (nombre ILIKE '${searchPattern}' OR whatsapp ILIKE '${searchPattern}' OR email ILIKE '${searchPattern}')
AND (${estadoFilter})
AND (${lead_tipo ? `lead_tipo = '${lead_tipo}'` : 'true'})
AND (${origen ? `origen = '${origen}'` : 'true'});`;

return [{json: {queryList, queryCount, limit, offset}}];

const listData = $('get_leads').all();
const countData = $('count_leads').all();
const total = countData[0]?.json?.total || 0;
const items = listData.map(row => row.json);

return [{json: {success: true, items: items, total: parseInt(total), count: items.length}}];
